import React from 'react';
import { Link } from 'react-router-dom';
import './Hero.css';

const Hero = () => {
  return (
    <section className="hero">
      <div className="container">
        <div className="hero-content">
          <h1 className="hero-title">
            We turn founder led agency businesses into highly profitable, cash confident companies
          </h1>
          <p className="hero-subtitle">
            Go from making gut based decisions to having total financial clarity
          </p>
          <Link to="/contact" className="btn-primary btn-large">
            Schedule a Call
          </Link>
        </div>
      </div>
    </section>
  );
};

export default Hero;
